package ir.tahamohamadi.resume; import ir.tahamohamadi.common.domain.ContentStatus; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*; import java.time.*; import java.util.*;
@Entity @Table(name="resume_entry") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class ResumeEntry extends AuditedSoftDeletableEntity { @Enumerated(EnumType.STRING) @Column(name="entry_type",nullable=false) private ResumeEntryType entryType; @Enumerated(EnumType.STRING) @Column(nullable=false) private ContentStatus status; @Column(name="started_on",nullable=false) private LocalDate startedOn; @Column(name="ended_on") private LocalDate endedOn; @Column(name="is_current",nullable=false) private boolean current; @Column(name="sort_order",nullable=false) private int sortOrder; private ResumeEntry(UUID id,ResumeEntryType type,LocalDate started,LocalDate ended,boolean current,int order,Instant at){initialize(id,at);entryType=Objects.requireNonNull(type,"type");startedOn=Objects.requireNonNull(started,"startedOn");if(ended!=null&&ended.isBefore(started))throw new IllegalArgumentException("endedOn must not precede startedOn");if(current&&ended!=null)throw new IllegalArgumentException("current entries cannot have endedOn");if(order<0)throw new IllegalArgumentException("sortOrder must be nonnegative");endedOn=ended;this.current=current;sortOrder=order;status=ContentStatus.DRAFT;} public static ResumeEntry create(UUID id,ResumeEntryType type,LocalDate started,LocalDate ended,boolean current,int order,Instant at){return new ResumeEntry(id,type,started,ended,current,order,at);} public void publish(){status=ContentStatus.PUBLISHED;} public void archive(){status=ContentStatus.ARCHIVED;} }
